import React, { useEffect, useState } from "react";
import { Table, Button, Avatar, Tooltip, Select } from "antd";
import { useDispatch, useSelector } from "react-redux";
import { Link } from "react-router-dom";
import { getB2bCustomers } from "../../features/b2b/b2bSlice";
import {
  Search,
  Mail,
  ExternalLink,
  Phone,
  Users,
  ShieldCheck,
  ShieldAlert,
} from "lucide-react";

const B2bCustomerList = () => {
  const dispatch = useDispatch();
  const [searchText, setSearchText] = useState("");
  const [filterType, setFilterType] = useState("all");
  const [filterVerified, setFilterVerified] = useState("all");

  useEffect(() => {
    const params = {};
    if (filterType !== "all") params.customerType = filterType;
    if (filterVerified !== "all") params.isVerified = filterVerified;
    if (searchText) params.search = searchText;

    dispatch(getB2bCustomers(params));
  }, [dispatch, searchText, filterType, filterVerified]);

  const { customers, isLoading } = useSelector((state) => state.b2b);

  const columns = [
    {
      title: "Institution / Client",
      dataIndex: "institutionName",
      render: (text, record) => (
        <div className="flex items-center gap-4 group">
          <Avatar
            size={48}
            src={`https://api.dicebear.com/7.x/initials/svg?seed=${text || record.lastname}&backgroundColor=f8fafc&textColor=2563eb&bold=true`}
            className="rounded-xl border border-slate-100 shadow-sm"
          />
          <div className="flex flex-col">
            <span className="font-bold text-black text-[16px] leading-tight">
              {text || "Individual / No Inst."}
            </span>
            <span className="text-[12px] text-slate-400 mt-1 font-medium">
              {(record.firstname || "") + " " + (record.lastname || "")}
            </span>
          </div>
        </div>
      ),
    },
    {
      title: "Type & Verification",
      dataIndex: "customerType",
      render: (type, record) => (
        <div className="flex flex-col gap-1.5">
          <span className="px-3 py-1 rounded-lg bg-slate-50 border border-slate-100 text-[11px] font-black text-slate-600 w-fit uppercase tracking-wider">
            {type?.replace(/_/g, " ") || "UNKNOWN"}
          </span>
          <div className="flex items-center gap-1.5">
            {record.isVerified ? (
              <>
                <ShieldCheck size={14} className="text-emerald-500" />
                <span className="text-[11px] text-emerald-600 font-bold">
                  Verified B2B
                </span>
              </>
            ) : (
              <>
                <ShieldAlert size={14} className="text-amber-500 animate-pulse" />
                <span className="text-[11px] text-amber-600 font-bold">
                  Pending Verification
                </span>
              </>
            )}
          </div>
        </div>
      ),
    },
    {
      title: "Email & Contact",
      dataIndex: "email",
      render: (text, record) => (
        <div className="flex flex-col gap-1">
          <div className="flex items-center gap-2">
            <Mail size={14} className="text-slate-400" />
            <span className="text-[14px] text-black font-medium">{text}</span>
          </div>
          <div className="flex items-center gap-2">
            <Phone size={14} className="text-slate-400" />
            <span className="text-[13px] text-slate-500 font-medium">
              {record.mobile || "No phone"}
            </span>
          </div>
        </div>
      ),
    },
    {
      title: "Credit Terms",
      dataIndex: "paymentTerms",
      render: (terms, record) => (
        <div className="flex flex-col gap-0.5">
          <span className="font-bold text-slate-800 text-[14px]">{terms}</span>
          <span className="text-[12px] text-slate-400 font-medium">
            Limit: {parseFloat(record.creditLimit || 0).toLocaleString()} ETB
          </span>
        </div>
      ),
    },
    {
      title: "Actions",
      dataIndex: "id",
      render: (id) => (
        <div className="flex items-center gap-2">
          <Tooltip title="View Account Profile">
            <Link to={`/admin/b2b/customers/${id}`}>
              <Button
                type="text"
                icon={<ExternalLink size={18} />}
                className="text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl w-10 h-10 flex items-center justify-center border border-transparent hover:border-blue-100"
              />
            </Link>
          </Tooltip>
        </div>
      ),
    },
  ];

  const dataSource =
    customers?.map((usr, i) => ({
      key: usr.id || i,
      id: usr.id,
      firstname: usr.firstname,
      lastname: usr.lastname,
      institutionName: usr.institutionName,
      customerType: usr.customerType,
      isVerified: usr.isVerified,
      email: usr.email,
      mobile: usr.mobile,
      paymentTerms: usr.paymentTerms,
      creditLimit: usr.creditLimit,
    })) || [];

  return (
    <div className="space-y-8 pb-12">
      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-[28px] font-bold text-slate-900 tracking-tight">
            Wholesale Accounts
          </h1>
          <p className="text-[15px] text-slate-500 mt-1 font-medium">
            Verify and manage credit facilities for hospital and pharmacy procurement profiles.
          </p>
        </div>
        <div className="relative w-full sm:w-80">
          <Search
            className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"
            size={18}
          />
          <input
            type="text"
            placeholder="Search institution or contact..."
            className="pl-10 pr-4 h-11 w-full bg-white border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500/20 text-[14px] font-medium"
            onChange={(e) => setSearchText(e.target.value)}
          />
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-slate-100 overflow-hidden shadow-sm">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center p-6 border-b border-slate-50 gap-4">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-blue-50 rounded-xl text-blue-600">
              <Users size={20} />
            </div>
            <div>
              <span className="text-[15px] font-bold text-black border-slate-100 pr-4 mr-4 border-r">
                B2B Institutions
              </span>
              <span className="text-[14px] text-slate-500 font-medium">
                Active Buyers:{" "}
                <span className="text-black font-bold">{dataSource.length}</span>
              </span>
            </div>
          </div>
          <div className="flex flex-wrap items-center gap-4">
            <div className="flex items-center gap-2">
              <span className="text-[13px] font-bold text-slate-400 uppercase tracking-widest">
                Type:
              </span>
              <Select
                defaultValue="all"
                onChange={(val) => setFilterType(val)}
                className="w-44 modern-select"
                bordered={false}
              >
                <Select.Option value="all">All Types</Select.Option>
                <Select.Option value="HOSPITAL">Hospital</Select.Option>
                <Select.Option value="CLINIC">Clinic</Select.Option>
                <Select.Option value="PHARMACY">Pharmacy</Select.Option>
                <Select.Option value="MEDICAL_LABORATORY">Lab</Select.Option>
                <Select.Option value="NGO">NGO</Select.Option>
              </Select>
            </div>

            <div className="flex items-center gap-2">
              <span className="text-[13px] font-bold text-slate-400 uppercase tracking-widest">
                Status:
              </span>
              <Select
                defaultValue="all"
                onChange={(val) => setFilterVerified(val)}
                className="w-44 modern-select"
                bordered={false}
              >
                <Select.Option value="all">All Accounts</Select.Option>
                <Select.Option value="true">Verified Only</Select.Option>
                <Select.Option value="false">Pending Verification</Select.Option>
              </Select>
            </div>
          </div>
        </div>

        <Table
          columns={columns}
          dataSource={dataSource}
          loading={isLoading}
          pagination={{
            pageSize: 10,
            className: "px-6 py-4",
          }}
          className="modern-table"
        />
      </div>

      <style>{`
        .modern-select .ant-select-selector {
          background: #f8fafc !important;
          border-radius: 12px !important;
          border: 1px solid #e2e8f0 !important;
          padding: 0 16px !important;
          height: 42px !important;
          display: flex !important;
          align-items: center !important;
        }
        .modern-table .ant-table-thead > tr > th {
          background: #fff !important;
          font-weight: 700 !important;
          font-size: 14px !important;
          color: #64748b !important;
          text-transform: uppercase !important;
          letter-spacing: 0.05em !important;
          border-bottom: 2px solid #f1f5f9 !important;
          padding: 16px 24px !important;
        }
        .modern-table .ant-table-tbody > tr > td {
          padding: 20px 24px !important;
          border-bottom: 1px solid #f8fafc !important;
        }
      `}</style>
    </div>
  );
};

export default B2bCustomerList;
